      options: [{ id: `A`, text: `<em>Gothic</em>—` }, { id: `B`, text: `<em>Gothic</em>` }, { id: `C`, text: `<em>Gothic</em>,` }, { id: `D`, text: `<em>Gothic</em>;` }],
