      options: [{ id: `A`, text: `painting, <em>St. Elmo's Fire</em>,` }, { id: `B`, text: `painting <em>St. Elmo's Fire</em>,` }, { id: `C`, text: `painting <em>St. Elmo's Fire</em>` }, { id: `D`, text: `painting, <em>St. Elmo's Fire</em>` }],
